     1→/**
     2→ * Critical Path Analysis Utilities
     3→ *
     4→ * Implements Critical Path Method (CPM) algorithm to identify the longest
     5→ * dependency chain in a project, which determines the minimum project duration.
     6→ *
     7→ * Tasks on the critical path have zero slack time - any delay directly impacts
     8→ * the project end date.
     9→ */
    10→
    11→import type { Task } from '../types';
    12→import { logger } from '../services/logger';
    13→
    14→const log = logger.module('CriticalPath');
    15→
    16→interface TaskSchedule {
    17→  taskId: string;
    18→  earliestStart: number; // Days from project start
    19→  earliestFinish: number;
    20→  latestStart: number;
    21→  latestFinish: number;
    22→  slack: number; // latestStart - earliestStart (or latestFinish - earliestFinish)
    23→  duration: number; // Days between start and due
    24→}
    25→
    26→/**
    27→ * Convert date string to day number (days from project start)
    28→ */
    29→function dateToDays(dateStr: string | null, projectStart: Date): number {
    30→  if (!dateStr) return 0;
    31→
    32→  const [year, month, day] = dateStr.split('-').map(Number);
    33→  const date = new Date(year, month - 1, day);
    34→
    35→  const diffTime = date.getTime() - projectStart.getTime();
    36→  return Math.max(0, Math.round(diffTime / (1000 * 60 * 60 * 24)));
    37→}
    38→
    39→/**
    40→ * Calculate task duration in days
    41→ */
    42→function getTaskDuration(task: Task): number {
    43→  if (!task.startDate || !task.dueDate) return 1; // Default 1 day if dates missing
    44→
    45→  const [y1, m1, d1] = task.startDate.split('-').map(Number);
    46→  const [y2, m2, d2] = task.dueDate.split('-').map(Number);
    47→
    48→  const start = new Date(y1, m1 - 1, d1);
    49→  const due = new Date(y2, m2 - 1, d2);
    50→
    51→  const diffTime = due.getTime() - start.getTime();
    52→  return Math.max(1, Math.round(diffTime / (1000 * 60 * 60 * 24)) + 1); // +1 to include end day
    53→}
    54→
    55→/**
    56→ * Build dependency graph
    57→ */
    58→function buildDependencyGraph(tasks: Task[]): Map<string, string[]> {
    59→  const graph = new Map<string, string[]>();
    60→
    61→  tasks.forEach(task => {
    62→    if (!graph.has(task.id)) {
    63→      graph.set(task.id, []);
    64→    }
    65→
    66→    task.dependencies?.forEach(dep => {
    67→      if (!graph.has(dep.taskId)) {
    68→        graph.set(dep.taskId, []);
    69→      }
    70→      // dep.taskId → task.id (blocker → dependent)
    71→      graph.get(dep.taskId)!.push(task.id);
    72→    });
    73→  });
    74→
    75→  return graph;
    76→}
    77→
    78→/**
    79→ * Forward pass: Calculate earliest start/finish for each task
    80→ */
    81→function forwardPass(
    82→  tasks: Task[],
    83→  projectStart: Date,
    84→  _graph: Map<string, string[]>
    85→): Map<string, TaskSchedule> {
    86→  const schedules = new Map<string, TaskSchedule>();
    87→  const processed = new Set<string>();
    88→
    89→  // Initialize all tasks
    90→  tasks.forEach(task => {
    91→    const duration = getTaskDuration(task);
    92→    const earliestStart = task.startDate ? dateToDays(task.startDate, projectStart) : 0;
    93→
    94→    schedules.set(task.id, {
    95→      taskId: task.id,
    96→      earliestStart,
    97→      earliestFinish: earliestStart + duration,
    98→      latestStart: 0, // Will be calculated in backward pass
    99→      latestFinish: 0, // Will be calculated in backward pass
   100→      slack: 0, // Will be calculated after backward pass
   101→      duration,
   102→    });
   103→  });
   104→
   105→  // Topological sort and calculate earliest times
   106→  function processTask(taskId: string) {
   107→    if (processed.has(taskId)) return;
   108→
   109→    const task = tasks.find(t => t.id === taskId);
   110→    if (!task) return;
   111→
   112→    // Process all dependencies first
   113→    task.dependencies?.forEach(dep => {
   114→      processTask(dep.taskId);
   115→    });
   116→
   117→    // Calculate earliest start based on dependencies
   118→    let maxEarliestFinish = task.startDate ? dateToDays(task.startDate, projectStart) : 0;
   119→
   120→    task.dependencies?.forEach(dep => {
   121→      const depSchedule = schedules.get(dep.taskId);
   122→      if (!depSchedule) return;
   123→
   124→      let depFinish = 0;
   125→      switch (dep.type) {
   126→        case 'finish-to-start':
   127→          depFinish = depSchedule.earliestFinish + (dep.lag || 0);
   128→          break;
   129→        case 'start-to-start':
   130→          depFinish = depSchedule.earliestStart + (dep.lag || 0);
   131→          break;
   132→        case 'finish-to-finish':
   133→          // This task must finish when dep finishes, so work backwards
   134→          depFinish = depSchedule.earliestFinish + (dep.lag || 0) - schedules.get(taskId)!.duration;
   135→          break;
   136→        case 'start-to-finish':
   137→          // This task must finish when dep starts, so work backwards
   138→          depFinish = depSchedule.earliestStart + (dep.lag || 0) - schedules.get(taskId)!.duration;
   139→          break;
   140→      }
   141→
   142→      maxEarliestFinish = Math.max(maxEarliestFinish, depFinish);
   143→    });
   144→
   145→    const schedule = schedules.get(taskId)!;
   146→    schedule.earliestStart = maxEarliestFinish;
   147→    schedule.earliestFinish = schedule.earliestStart + schedule.duration;
   148→
   149→    processed.add(taskId);
   150→  }
   151→
   152→  // Process all tasks
   153→  tasks.forEach(task => processTask(task.id));
   154→
   155→  return schedules;
   156→}
   157→
   158→/**
   159→ * Backward pass: Calculate latest start/finish for each task
   160→ */
   161→function backwardPass(
