     1→/**
     2→ * GanttTimeline Component
     3→ * Main SVG timeline canvas with task bars and grid
     4→ */
     5→
     6→import { useRef, useEffect, useState } from 'react';
     7→import { Download } from 'lucide-react';
     8→import type { Task, TaskStatus, ProjectBaseline } from '../../types';
     9→import { TimelineScale } from './TimelineScale';
    10→import { TaskBar } from './TaskBar';
    11→import { DependencyLine } from './DependencyLine';
    12→import { ExportDialog } from './ExportDialog';
    13→import { ROW_HEIGHT, dateToX, type ZoomLevel } from './utils';
    14→import { getBaselineTask } from '../../utils/baseline';
    15→
    16→interface GanttTimelineProps {
    17→  tasks: Task[];
    18→  startDate: Date;
    19→  endDate: Date;
    20→  zoom: ZoomLevel;
    21→  onTaskUpdate: (taskId: string, updates: Partial<Task>) => void;
    22→  onTaskClick: (task: Task) => void;
    23→  criticalTaskIds?: string[]; // Phase 1.3: Critical path
    24→  baseline?: ProjectBaseline | null; // Phase 1.4: Baseline comparison
    25→}
    26→
    27→export function GanttTimeline({
    28→  tasks,
    29→  startDate,
    30→  endDate,
    31→  zoom,
    32→  onTaskUpdate,
    33→  onTaskClick,
    34→  criticalTaskIds = [],
    35→  baseline = null,
    36→}: GanttTimelineProps) {
    37→  const containerRef = useRef<HTMLDivElement>(null);
    38→  const timelineRef = useRef<HTMLDivElement>(null);
    39→  const [containerWidth, setContainerWidth] = useState(0);
    40→  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false);
    41→  const [expandedTaskIds, setExpandedTaskIds] = useState<Set<string>>(new Set());
    42→
    43→  // Calculate timeline width based on date range
    44→  const timelineWidth = dateToX(endDate, startDate, zoom);
    45→
    46→  // Update container width on resize
    47→  useEffect(() => {
    48→    if (!containerRef.current) return;
    49→
    50→    const updateWidth = () => {
    51→      if (containerRef.current) {
    52→        setContainerWidth(containerRef.current.clientWidth);
    53→      }
    54→    };
    55→
    56→    updateWidth();
    57→
    58→    const observer = new ResizeObserver(updateWidth);
    59→    observer.observe(containerRef.current);
    60→
    61→    return () => observer.disconnect();
    62→  }, []);
    63→
    64→  // Group tasks by status (swimlanes)
    65→  const groupedTasks = tasks.reduce((acc, task) => {
    66→    if (!acc[task.status]) {
    67→      acc[task.status] = [];
    68→    }
    69→    acc[task.status].push(task);
    70→    return acc;
    71→  }, {} as Record<TaskStatus, Task[]>);
    72→
    73→  const statuses: TaskStatus[] = ['backlog', 'todo', 'inprogress', 'review', 'done'];
    74→  const swimlanes = statuses.map((status) => ({
    75→    status,
    76→    tasks: groupedTasks[status] || [],
    77→  }));
    78→
    79→  // Calculate today marker position
    80→  const todayX = dateToX(new Date(), startDate, zoom);
    81→  const isTodayVisible = todayX >= 0 && todayX <= timelineWidth;
    82→
    83→  // Create task lookup map for dependency rendering
    84→  const taskMap = new Map(tasks.map((task) => [task.id, task]));
    85→
    86→  // Create task position map (task ID -> row index)
    87→  const taskRowMap = new Map<string, number>();
    88→  swimlanes.forEach((swimlane, swimlaneIndex) => {
    89→    swimlane.tasks.forEach((task) => {
    90→      taskRowMap.set(task.id, swimlaneIndex);
    91→    });
    92→  });
    93→
    94→  // Status labels
    95→  const getStatusLabel = (status: TaskStatus): string => {
    96→    switch (status) {
    97→      case 'backlog':
    98→        return 'Backlog';
    99→      case 'todo':
   100→        return 'To Do';
   101→      case 'inprogress':
   102→        return 'In Progress';
   103→      case 'review':
   104→        return 'In Review';
   105→      case 'done':
   106→        return 'Done';
   107→      default:
   108→        return status;
   109→    }
   110→  };
   111→
   112→  // Helper: Convert subtasks to full Task objects with hierarchy
   113→  interface TaskWithHierarchy extends Task {
   114→    level: number;
   115→    parentId?: string;
   116→    hasSubtasks: boolean;
   117→  }
   118→
   119→  const buildTaskHierarchy = (tasks: Task[]): TaskWithHierarchy[] => {
   120→    const result: TaskWithHierarchy[] = [];
   121→
   122→    tasks.forEach((task) => {
   123→      // Add parent task
   124→      result.push({
   125→        ...task,
   126→        level: 0,
   127→        hasSubtasks: !!task.subtasks && task.subtasks.length > 0,
   128→      });
   129→
   130→      // Add subtasks if parent is expanded
   131→      if (task.subtasks && task.subtasks.length > 0 && expandedTaskIds.has(task.id)) {
   132→        task.subtasks.forEach((subtask) => {
   133→          // Convert Subtask to Task-like object
   134→          const subtaskAsTask: TaskWithHierarchy = {
   135→            id: subtask.id,
   136→            title: subtask.title,
   137→            description: subtask.description || '',
   138→            status: subtask.completed ? 'done' : 'todo',
   139→            created: subtask.createdAt,
   140→            startDate: null,
   141→            dueDate: subtask.dueDate || null,
   142→            priority: subtask.priority || 'medium',
   143→            tags: [],
   144→            order: subtask.order,
   145→            level: 1,
   146→            parentId: subtask.parentTaskId,
   147→            hasSubtasks: false,
   148→            progress: subtask.completed ? 100 : 0,
   149→            projectIds: [],
   150→          };
   151→          result.push(subtaskAsTask);
   152→        });
   153→      }
   154→    });
   155→
   156→    return result;
   157→  };
   158→
   159→  // Toggle expand/collapse for task
   160→  const toggleTaskExpansion = (taskId: string) => {
   161→    setExpandedTaskIds((prev) => {
   162→      const next = new Set(prev);
   163→      if (next.has(taskId)) {
   164→        next.delete(taskId);
   165→      } else {
   166→        next.add(taskId);
   167→      }
   168→      return next;
   169→    });
   170→  };
   171→
   172→  // Calculate summary bar dates for parent tasks
   173→  const calculateSummaryDates = (task: Task): { start: Date | null; end: Date | null } => {
   174→    if (!task.subtasks || task.subtasks.length === 0) {
   175→      return {
   176→        start: task.startDate ? new Date(task.startDate) : null,
   177→        end: task.dueDate ? new Date(task.dueDate) : null,
   178→      };
   179→    }
   180→
   181→    // Get all subtask dates
   182→    const subtaskDates = task.subtasks
   183→      .filter((st) => st.dueDate)
   184→      .map((st) => new Date(st.dueDate!));
   185→
   186→    if (subtaskDates.length === 0) {
   187→      return {
   188→        start: task.startDate ? new Date(task.startDate) : null,
   189→        end: task.dueDate ? new Date(task.dueDate) : null,
   190→      };
   191→    }
   192→
   193→    // Min and max dates
   194→    const minDate = new Date(Math.min(...subtaskDates.map((d) => d.getTime())));
   195→    const maxDate = new Date(Math.max(...subtaskDates.map((d) => d.getTime())));
   196→
   197→    return { start: minDate, end: maxDate };
   198→  };
   199→
   200→  return (
   201→    <>
   202→      {/* Export Dialog */}
   203→      <ExportDialog
   204→        isOpen={isExportDialogOpen}
   205→        onClose={() => setIsExportDialogOpen(false)}
   206→        tasks={tasks}
   207→        timelineElement={timelineRef.current}
   208→        dateRange={{ start: startDate, end: endDate }}
   209→        projectName="Project Timeline"
   210→      />
   211→
   212→      <div ref={containerRef} className="relative w-full overflow-auto">
   213→        {/* Toolbar */}
   214→        <div className="sticky top-0 z-30 bg-surface-light dark:bg-surface-dark border-b border-border-light dark:border-border-dark px-4 py-2 flex items-center justify-end gap-2">
   215→          <button
   216→            onClick={() => setIsExportDialogOpen(true)}
   217→            className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium bg-accent-magenta dark:bg-accent-cyan text-white dark:text-dark-background rounded-lg hover:bg-accent-magenta-dark dark:hover:bg-accent-cyan-dark transition-colors"
   218→          >
   219→            <Download className="w-4 h-4" />
   220→            Export
   221→          </button>
   222→        </div>
   223→
   224→        <div ref={timelineRef} style={{ width: Math.max(timelineWidth, containerWidth), minHeight: 400 }}>
   225→          {/* Timeline Scale */}
   226→          <TimelineScale
   227→            startDate={startDate}
   228→            endDate={endDate}
   229→            zoom={zoom}
   230→            width={Math.max(timelineWidth, containerWidth)}
   231→          />
   232→
   233→        {/* Dependency arrows (SVG overlay) */}
   234→        <svg
   235→          className="absolute top-0 left-0 pointer-events-none"
   236→          style={{ width: Math.max(timelineWidth, containerWidth), height: swimlanes.length * ROW_HEIGHT, marginTop: 0 }}
   237→        >
   238→          {tasks.flatMap((task) => {
   239→            if (!task.dependencies || task.dependencies.length === 0) return [];
   240→
   241→            return task.dependencies.map((dep) => {
   242→              const sourceTask = taskMap.get(dep.taskId); // The task this one depends on (blocker)
   243→              const targetTask = task; // Current task (blocked)
   244→              const sourceRowIndex = taskRowMap.get(dep.taskId);
   245→              const targetRowIndex = taskRowMap.get(task.id);
   246→
   247→              if (!sourceTask || sourceRowIndex === undefined || targetRowIndex === undefined) {
   248→                return null;
   249→              }
   250→
   251→              // Only render if both tasks have dates
   252→              if (!sourceTask.dueDate || !targetTask.startDate) {
   253→                return null;
   254→              }
   255→
   256→              return (
   257→                <DependencyLine
   258→                  key={`${task.id}-${dep.taskId}`}
   259→                  sourceTask={sourceTask}
   260→                  targetTask={targetTask}
   261→                  dependencyType={dep.type}
   262→                  lag={dep.lag}
   263→                  sourceRowIndex={sourceRowIndex}
   264→                  targetRowIndex={targetRowIndex}
   265→                  timelineStart={startDate}
   266→                  zoom={zoom}
   267→                />
   268→              );
   269→            });
   270→          })}
   271→        </svg>
   272→
   273→        {/* Swimlanes */}
   274→        <div className="relative" style={{ marginTop: 0 }}>
   275→          {swimlanes.map((swimlane) => {
   276→            // Build hierarchy for this swimlane
   277→            const hierarchyTasks = buildTaskHierarchy(swimlane.tasks);
   278→
   279→            return (
   280→              <div
   281→                key={swimlane.status}
   282→                className="relative border-b border-border-light dark:border-border-dark"
   283→                style={{ minHeight: ROW_HEIGHT }}
   284→              >
   285→                {/* Swimlane label */}
   286→                <div
   287→                  className="sticky left-0 z-10 flex items-center px-3 bg-surface-light dark:bg-surface-dark border-r border-border-light dark:border-border-dark"
   288→                  style={{ width: 150, minHeight: ROW_HEIGHT }}
   289→                >
   290→                  <span className="text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary">
   291→                    {getStatusLabel(swimlane.status)} ({swimlane.tasks.length})
   292→                  </span>
   293→                </div>
   294→
   295→                {/* Task bars with hierarchy */}
   296→                <div className="absolute inset-0" style={{ left: 150 }}>
   297→                  {hierarchyTasks
   298→                    .filter((task) => task.startDate || task.dueDate || task.hasSubtasks) // Show tasks with dates or parents with subtasks
   299→                    .map((task, index) => {
   300→                      // For parent tasks with collapsed subtasks, show summary bar
   301→                      const summaryDates = task.hasSubtasks && !expandedTaskIds.has(task.id)
   302→                        ? calculateSummaryDates(task)
   303→                        : { start: task.startDate ? new Date(task.startDate) : null, end: task.dueDate ? new Date(task.dueDate) : null };
   304→
   305→                      // Use summary dates if available
   306→                      const displayTask = task.hasSubtasks && !expandedTaskIds.has(task.id)
   307→                        ? {
   308→                            ...task,
   309→                            startDate: summaryDates.start?.toISOString().split('T')[0] || task.startDate,
   310→                            dueDate: summaryDates.end?.toISOString().split('T')[0] || task.dueDate,
   311→                          }
   312→                        : task;
   313→
   314→                      return (
   315→                        <TaskBar
   316→                          key={task.id}
   317→                          task={displayTask}
   318→                          startDate={startDate}
   319→                          zoom={zoom}
   320→                          rowY={index * 40} // Stack vertically
   321→                          onUpdate={onTaskUpdate}
   322→                          onClick={onTaskClick}
