   245→        });
   246→
   247→        // P1: Trigger automation rules for 'task.created'
   248→        setTimeout(async () => {
   249→          const { useAutomationStore } = await import('./useAutomationStore');
   250→          const automationStore = useAutomationStore.getState();
   251→          const context: AutomationContext = {
   252→            taskId: newTask.id,
   253→            timestamp: new Date().toISOString(),
   254→          };
   255→
   256→          const logs = await evaluateRules(
   257→            automationStore.rules,
   258→            'task.created',
   259→            newTask,
