   267→      updateTask: (id, updates) => {
   268→        const oldTask = get().tasks.find((t) => t.id === id);
   269→        if (!oldTask) return;
   270→
   271→        // Phase 1.2: Check if date changes trigger dependent shifts
   272→        // Note: This only updates the primary task. Components must call
   273→        // calculateDependentShifts separately and show confirmation dialog
   274→        // before calling applyDependentShifts.
   275→
   276→        set((state) => ({
   277→          tasks: state.tasks.map((task) =>
   278→            task.id === id ? { ...task, ...updates } : task
   279→          ),
   280→        }));
   281→
   282→        // Log updates (track specific fields)
   283→        Object.keys(updates).forEach((field) => {
   284→          if (field !== 'activityLog') { // Don't log the log itself
   285→            get().logActivity(id, {
   286→              action: 'updated',
   287→              field,
   288→              oldValue: String(oldTask[field as keyof Task] ?? ''),
   289→              newValue: String(updates[field as keyof Task] ?? ''),
   290→            });
   291→          }
   292→        });
   293→      },
   294→
   295→      deleteTask: (id) =>
   296→        set((state) => ({
   297→          tasks: state.tasks.filter((task) => task.id !== id),
   298→        })),
   299→
   300→      moveTask: (id, newStatus) => {
   301→        const oldTask = get().tasks.find((t) => t.id === id);
   302→        if (!oldTask) return;
   303→
   304→        // PHASE 5 PART 6: Validate dependencies before moving to "done"
   305→        if (newStatus === 'done') {
   306→          const blockers = get().getBlockers(id);
   307→          const incompleteBlockers = blockers.filter((b) => b.status !== 'done');
   308→
   309→          if (incompleteBlockers.length > 0) {
   310→            log.warn('Cannot complete task: blocked by incomplete tasks', {
   311→              taskId: id,
   312→              taskTitle: oldTask.title,
   313→              blockerCount: incompleteBlockers.length
   314→            });
   315→            const blockerNames = incompleteBlockers.map(b => b.title).slice(0, 2).join(', ');
   316→            const suffix = incompleteBlockers.length > 2 ? ` and ${incompleteBlockers.length - 2} more` : '';
   317→            toast.warning(
   318→              `Cannot complete "${oldTask.title}"`,
   319→              `Blocked by: ${blockerNames}${suffix}`
   320→            );
   321→            return; // Prevent move
   322→          }
   323→        }
   324→
   325→        // PHASE A: Track when task is completed (for auto-archive)
   326→        const updates: Partial<Task> = { status: newStatus };
   327→        if (newStatus === 'done' && oldTask.status !== 'done') {
   328→          updates.lastCompletedAt = new Date().toISOString();
   329→        }
   330→
   331→        // P1: AUTO-GENERATE NEXT RECURRING INSTANCE
   332→        // If completing a recurring task instance, generate next occurrence
   333→        const isCompletingRecurringInstance = newStatus === 'done' && oldTask.recurrenceId;
   334→
   335→        set((state) => ({
   336→          tasks: state.tasks.map((task) =>
   337→            task.id === id ? { ...task, ...updates } : task
   338→          ),
   339→        }));
   340→
   341→        // Generate next instance after state update (avoid mutation during update)
   342→        if (isCompletingRecurringInstance) {
   343→          setTimeout(() => {
   344→            // Pass the completed task instance for recurFromCompletion calculation
   345→            const completedTask = get().tasks.find((t) => t.id === id);
   346→            get().generateNextRecurringInstance(oldTask.recurrenceId!, completedTask);
   347→          }, 0);
   348→        }
   349→
   350→        // Log move
   351→        get().logActivity(id, {
   352→          action: 'moved',
   353→          field: 'status',
   354→          oldValue: oldTask.status,
   355→          newValue: newStatus,
   356→        });
   357→
   358→        // P1: Trigger automation rules for 'task.moved' and potentially 'task.completed'
   359→        setTimeout(async () => {
   360→          const { useAutomationStore } = await import('./useAutomationStore');
   361→          const automationStore = useAutomationStore.getState();
   362→          const updatedTask = get().tasks.find((t) => t.id === id);
   363→          if (!updatedTask) return;
   364→
   365→          const context: AutomationContext = {
   366→            taskId: id,
   367→            previousStatus: oldTask.status,
   368→            newStatus,
   369→            timestamp: new Date().toISOString(),
   370→          };
   371→
   372→          // Trigger 'task.moved' for all status changes
   373→          const movedLogs = await evaluateRules(
   374→            automationStore.rules,
   375→            'task.moved',
   376→            updatedTask,
   377→            context,
   378→            get()
   379→          );
   380→          movedLogs.forEach((log) => automationStore.addExecutionLog(log));
   381→
   382→          // Also trigger 'task.completed' if moved to done
   383→          if (newStatus === 'done') {
   384→            const completedLogs = await evaluateRules(
   385→              automationStore.rules,
   386→              'task.completed',
   387→              updatedTask,
   388→              context,
   389→              get()
   390→            );
   391→            completedLogs.forEach((log) => automationStore.addExecutionLog(log));
   392→          }
   393→        }, 0);
   394→      },
