   415→      setTaskRecurrence: (taskId, recurrence) => {
   416→        const task = get().tasks.find((t) => t.id === taskId);
   417→        if (!task) {
   418→          log.warn('Task not found for recurrence', { taskId });
   419→          return;
   420→        }
   421→
   422→        // Mark as recurring parent and calculate next occurrence
   423→        const updates: Partial<Task> = {
   424→          recurrence,
   425→          isRecurringParent: recurrence ? true : undefined,
   426→          nextOccurrence: recurrence ? updateNextOccurrence({ ...task, recurrence }) : undefined,
   427→        };
   428→
   429→        get().updateTask(taskId, updates);
