   434→      generateNextRecurringInstance: (parentTaskId, lastCompletedInstance) => {
   435→        const parentTask = get().tasks.find((t) => t.id === parentTaskId);
   436→        if (!parentTask || !parentTask.isRecurringParent) {
   437→          log.warn('Not a recurring parent task', { parentTaskId });
   438→          return;
   439→        }
   440→
   441→        // Check if we should generate next instance
   442→        if (!shouldGenerateNextInstance(parentTask, get().tasks)) {
   443→          log.debug('Next instance not needed yet', { parentTaskId });
   444→          return;
   445→        }
   446→
   447→        // Generate new instance (pass completed instance for recurFromCompletion)
   448→        const instance = generateNextInstance(parentTask, lastCompletedInstance);
   449→        if (!instance) {
   450→          log.debug('No more instances to generate (series ended)', { parentTaskId });
   451→          return;
   452→        }
   453→
   454→        // Add instance to tasks
   455→        set((state) => ({
   456→          tasks: [...state.tasks, instance],
   457→        }));
   458→
   459→        // Update parent's nextOccurrence
   460→        const nextOccurrence = updateNextOccurrence(parentTask);
   461→        get().updateTask(parentTaskId, { nextOccurrence });
   462→
   463→        log.info('Generated recurring task instance', {
   464→          parentId: parentTaskId,
   465→          instanceId: instance.id,
   466→          dueDate: instance.dueDate,
   467→        });
   468→      },
