   548→      replaceAllColumns: (newColumns: Omit<KanbanColumn, 'id' | 'order'>[]) => {
   549→        const state = get();
   550→
   551→        // Save undo entry BEFORE making changes
   552→        get().addToUndoHistory({
   553→          action: 'replaceAllColumns',
   554→          description: `Applied template`,
   555→          previousState: {
   556→            columns: state.columns,
   557→            tasks: state.tasks,
   558→          },
