   560→
   561→        // Generate new columns with fresh IDs and correct order
   562→        const columns: KanbanColumn[] = newColumns.map((col, index) => ({
   563→          ...col,
   564→          id: `col-${Date.now()}-${index}`,
   565→          order: index,
   566→        }));
   567→
   568→        if (columns.length === 0) {
   569→          log.error('No columns provided for replacement');
   570→          return;
   571→        }
   572→
   573→        // Smart mapping: Try to preserve task positions based on column titles
   574→        const tasks = state.tasks.map(task => {
   575→          const oldColumn = state.columns.find(c => c.id === task.status);
   576→          if (!oldColumn) {
   577→            // Task has invalid status, move to first column
   578→            return { ...task, status: columns[0].id as TaskStatus };
   579→          }
   580→
   581→          // Try exact match first (case-insensitive)
   582→          let newColumn = columns.find(c =>
   583→            c.title.toLowerCase() === oldColumn.title.toLowerCase()
   584→          );
   585→
   586→          // If no exact match, try partial match (contains)
   587→          if (!newColumn) {
   588→            newColumn = columns.find(c =>
   589→              c.title.toLowerCase().includes(oldColumn.title.toLowerCase()) ||
   590→              oldColumn.title.toLowerCase().includes(c.title.toLowerCase())
   591→            );
   592→          }
   593→
   594→          // Fallback: first column
   595→          if (!newColumn) {
   596→            newColumn = columns[0];
   597→          }
   598→
   599→          return { ...task, status: newColumn.id as TaskStatus };
   600→        });
   601→
   602→        set({ columns, tasks });
