  1132→      addDependency: (taskId, dependency) => {
  1133→        // Prevent self-dependency
  1134→        if (taskId === dependency.taskId) {
  1135→          log.error('Task cannot depend on itself', { taskId });
  1136→          return;
  1137→        }
  1138→
  1139→        // Check for circular dependency
  1140→        const task = get().tasks.find(t => t.id === taskId);
  1141→        if (!task) {
  1142→          log.error('Task not found', { taskId });
  1143→          return;
  1144→        }
  1145→
  1146→        const wouldCreateCycle = (currentTaskId: string, blockerTaskId: string, visited = new Set<string>()): boolean => {
  1147→          if (currentTaskId === blockerTaskId) return true;
  1148→          if (visited.has(currentTaskId)) return false; // Already checked
  1149→
  1150→          visited.add(currentTaskId);
  1151→
  1152→          // Get the blocker task's dependencies
  1153→          const blockerTask = get().tasks.find(t => t.id === blockerTaskId);
  1154→          if (!blockerTask || !blockerTask.dependencies) return false;
  1155→
  1156→          // Check if blocker depends on current (directly or indirectly)
  1157→          return blockerTask.dependencies.some(dep => wouldCreateCycle(currentTaskId, dep.taskId, visited));
  1158→        };
  1159→
  1160→        if (wouldCreateCycle(taskId, dependency.taskId)) {
  1161→          log.error('Circular dependency detected', { taskId, dependsOn: dependency.taskId });
  1162→          return;
  1163→        }
  1164→
  1165→        // Add dependency to task
  1166→        set((state) => ({
  1167→          tasks: state.tasks.map(t => {
  1168→            if (t.id === taskId) {
  1169→              const existingDeps = t.dependencies || [];
