     1→// ==================== CORE TYPES ====================
     2→
     3→import type { CustomFieldsMap } from './customFields';
     4→
     5→export type ViewMode = 'monthly' | 'weekly' | 'daily' | 'agenda';
     6→export type TaskStatus = 'backlog' | 'todo' | 'inprogress' | 'review' | 'done';
     7→export type TaskPriority = 'low' | 'medium' | 'high';
     8→
     9→// ==================== PROJECT CONTEXT TYPES ====================
    10→// Global project/context filter system for scoping all entities
    11→
    12→/**
    13→ * ProjectContext - A hierarchical project/context for organizing all entities.
    14→ * Used by the global project filter dropdown to scope the entire platform.
    15→ *
    16→ * Note: This is distinct from the PM-focused `Project` interface used in Gantt/resource planning.
    17→ * ProjectContext is for user-facing organization; Project is for PM tracking features.
    18→ */
    19→export interface ProjectContext {
    20→  id: string;
    21→  name: string;
    22→  parentId: string | null;       // null = root project (enables hierarchy)
    23→  color: string;                 // Hex color for visual identification
    24→  icon?: string;                 // Optional emoji/icon (e.g., "🏠", "💼")
    25→  description?: string;          // Optional project description
    26→  archivedAt?: string;           // ISO date - soft delete (null = active)
    27→  createdAt: string;             // ISO date
    28→  updatedAt: string;             // ISO date
    29→}
    30→
    31→export interface ProjectContextState {
    32→  // Projects data
    33→  projects: ProjectContext[];
    34→
    35→  // Global filter state (empty = "All")
    36→  activeProjectIds: string[];
    37→}
    38→
    39→// ==================== WIDGET DATA TYPES ====================
    40→
    41→export interface CalendarEvent {
    42→  id: string;
    43→  title: string;
    44→  description?: string;
    45→  startTime?: string; // "14:00" (24-hour format)
    46→  endTime?: string;   // "15:30"
    47→  isAllDay?: boolean; // default true if no times specified
    48→
    49→  // Project context (global filter system)
    50→  projectIds: string[];  // Array for multi-project support; empty = uncategorized
    51→
    52→  // Recurrence
    53→  recurrence?: {
    54→    frequency: 'daily' | 'weekly' | 'monthly' | 'yearly';
    55→    interval: number; // e.g., every 2 weeks
    56→    daysOfWeek?: number[]; // 0=Sun, 1=Mon, etc. (for weekly)
    57→    dayOfMonth?: number; // 1-31 (for monthly)
    58→    endType: 'never' | 'after' | 'until';
    59→    endCount?: number; // if endType='after'
    60→    endDate?: string; // if endType='until' (YYYY-MM-DD)
    61→  };
    62→  recurrenceId?: string; // For recurring event instances (parent event ID)
    63→  recurrenceException?: boolean; // True if this instance was edited
    64→
    65→  // Multi-day
    66→  endDate?: string; // YYYY-MM-DD (if different from startDate)
    67→
    68→  // Reminders
    69→  reminders?: number[]; // Minutes before event (e.g., [15, 60])
    70→
    71→  // Location
    72→  location?: string;
    73→
    74→  // Multi-day rendering flags (internal, not persisted)
    75→  _isMultiDayPart?: boolean;
    76→  _isMultiDayFirst?: boolean;
    77→  _isMultiDayLast?: boolean;
    78→}
    79→
    80→export interface CalendarState {
    81→  events: Record<string, CalendarEvent[]>; // dateKey -> array of events
    82→  viewMode: ViewMode;
    83→  currentDate: Date;
    84→}
    85→
    86→export type DependencyType =
    87→  | 'finish-to-start'  // Task B starts when A finishes (default)
    88→  | 'start-to-start'   // Task B starts when A starts
    89→  | 'finish-to-finish' // Task B finishes when A finishes
    90→  | 'start-to-finish'; // Task B finishes when A starts (rare)
    91→
    92→export interface TaskDependency {
    93→  taskId: string;           // ID of dependent task
    94→  type: DependencyType;     // Type of dependency
    95→  lag: number;              // Lag time in days (can be negative for lead)
    96→}
    97→
    98→// Phase 1.4: Baseline snapshot for task (stored in project baseline)
    99→export interface BaselineTask {
   100→  id: string;
   101→  startDate: string | null;
   102→  dueDate: string | null;
   103→  progress: number;
   104→}
   105→
   106→// Phase 1.4: Project baseline snapshot
   107→export interface ProjectBaseline {
   108→  setAt: string;            // ISO date when baseline was set
   109→  tasks: BaselineTask[];    // Snapshot of all tasks at baseline time
   110→}
   111→
   112→// Phase 1.4: Variance status for baseline comparison
   113→export type VarianceStatus = 'ahead' | 'behind' | 'on-track';
   114→
   115→// Phase 3.1: Team member for task assignment
   116→export interface Member {
   117→  id: string;
   118→  name: string;
   119→  email?: string;
   120→  initials: string;        // Auto-generated from name
   121→  avatarColor: string;     // Hex color for avatar background
   122→  createdAt: string;       // ISO date
   123→}
   124→
   125→// Phase 3.2: File attachment for tasks
   126→export interface TaskAttachment {
   127→  id: string;
   128→  taskId: string;
   129→  filename: string;
   130→  fileType: string;        // MIME type (e.g., "image/png", "application/pdf")
   131→  fileSize: number;        // Bytes
   132→  dataUrl: string;         // Base64 data URI
   133→  uploadedAt: string;      // ISO date
   134→  uploadedBy?: string;     // Future: member ID
   135→}
   136→
   137→// Phase 4: Column definition for custom Kanban columns
   138→export interface KanbanColumn {
   139→  id: string;              // e.g., "backlog", "todo", or UUID for custom
   140→  title: string;           // e.g., "Backlog", "In Progress"
   141→  color: string;           // Tailwind class: "bg-status-info"
   142→  order: number;           // For drag-drop reordering
   143→  wipLimit?: number;       // Optional WIP constraint (e.g., 5 tasks max)
   144→}
   145→
   146→// Phase 4: Checklist item for subtasks
   147→export interface ChecklistItem {
   148→  id: string;
   149→  text: string;
   150→  completed: boolean;
   151→  order: number;
   152→  createdAt: string;       // ISO date
   153→}
   154→
   155→// Task Template for Recurring Tasks (P2)
   156→export interface TaskTemplate {
   157→  id: string;
   158→  name: string;                    // Template name (user-defined)
   159→  description: string;             // Template description
   160→  checklist?: ChecklistItem[];     // Checklist items (NOT completion status)
   161→  tags: string[];                  // Tags/labels
   162→  customFields?: CustomFieldsMap;  // Custom field values
   163→  createdAt: string;               // ISO date string
   164→  updatedAt?: string;              // ISO date string
   165→}
   166→
   167→// Phase 5: Subtask - Rich nested tasks within a card
   168→export interface Subtask {
   169→  id: string;
   170→  parentTaskId: string;
   171→  title: string;
   172→  description?: string;
   173→  completed: boolean;
   174→  priority?: TaskPriority;
   175→  dueDate?: string;       // YYYY-MM-DD
   176→  order: number;          // For manual sorting
   177→  createdAt: string;      // ISO date
   178→  completedAt?: string;   // ISO date (when marked complete)
   179→}
   180→
   181→// Phase 5: Simple task dependency (blocks/blocked-by)
   182→export interface SimpleTaskDependency {
   183→  id: string;
   184→  sourceTaskId: string; // Task that blocks
   185→  targetTaskId: string; // Task that is blocked
   186→  createdAt: string;    // ISO date
   187→}
   188→
   189→// Phase 4: Comment for task discussions
   190→export interface TaskComment {
   191→  id: string;
   192→  taskId: string;
   193→  text: string;            // Markdown supported
   194→  author: string;          // For future: user ID, for now: "You"
   195→  createdAt: string;       // ISO date
   196→  updatedAt?: string;      // ISO date (if edited)
   197→}
   198→
   199→// Phase 4: Activity log entry for tracking changes
   200→export interface ActivityLogEntry {
   201→  id: string;
   202→  timestamp: string;       // ISO date
   203→  action: 'created' | 'updated' | 'moved' | 'commented' | 'checklist_updated';
   204→  field?: string;          // e.g., "status", "priority"
   205→  oldValue?: string;
   206→  newValue?: string;
   207→  userId?: string;         // For future: "You" for now
   208→}
   209→
   210→// Undo system: History entry for undoing destructive actions
   211→export interface UndoHistoryEntry {
   212→  id: string;              // Unique ID for this action
   213→  timestamp: string;       // ISO date
   214→  action: 'deleteColumn' | 'replaceAllColumns' | 'deleteTask' | 'bulkDelete';
   215→  description: string;     // Human-readable: "Deleted column 'In Progress'"
   216→  previousState: {
   217→    columns: KanbanColumn[];
   218→    tasks: Task[];
   219→  };
   220→}
   221→
   222→export type EffortEstimate = 1 | 2 | 3 | 5 | 8 | 13; // Story points (Fibonacci)
   223→export type CustomStatus = 'in-review' | 'testing' | 'deployed' | 'blocked'; // Beyond base status
   224→
   225→// Phase 4: Card templates for quick task creation
   226→export interface CardTemplate {
   227→  id: string;
   228→  name: string;
   229→  icon: string;
   230→  description: string;           // Pre-filled description
   231→  defaultPriority: TaskPriority;
   232→  defaultTags: string[];
   233→  defaultColumn?: string;        // Optional default column
   234→  isBuiltIn: boolean;            // System templates vs user-created
   235→}
   236→
   237→export interface TimeTracking {
   238→  estimated?: number;           // Estimated hours
   239→  actual: number;               // Actual hours spent
   240→  activeTimerStart?: string;    // ISO date (null = timer not running)
   241→  timerHistory: Array<{         // Time tracking history log
   242→    id: string;
   243→    startTime: string;          // ISO date
   244→    endTime: string;            // ISO date
   245→    duration: number;           // Seconds
   246→  }>;
   247→}
   248→
   249→export interface Task {
   250→  id: string;
   251→  title: string;
   252→  description: string;
   253→  status: TaskStatus;
   254→  created: string; // ISO date string
   255→  startDate: string | null; // Date string YYYY-MM-DD
   256→  dueDate: string | null; // Date string YYYY-MM-DD
   257→  priority: TaskPriority;
   258→  tags: string[];
   259→  order?: number; // Position within status column for drag-drop
   260→
   261→  // Project context (global filter system)
   262→  projectIds: string[];  // Array for multi-project support; empty = uncategorized
   263→
   264→  // ENHANCED PM FIELDS:
   265→  dependencies?: TaskDependency[]; // Tasks this depends on
   266→  estimatedHours?: number;         // For resource planning
   267→  actualHours?: number;            // For EVM calculations
   268→  progress?: number;               // 0-100 percentage complete
   269→  isMilestone?: boolean;           // True for milestone markers
   270→  assignedTo?: string;             // Resource ID
   271→  baseline?: {                     // Original plan for comparison
   272→    startDate: string;
   273→    dueDate: string;
   274→  };
   275→  isOnCriticalPath?: boolean;      // Calculated field
   276→
   277→  // PHASE 4 FIELDS:
   278→  checklist?: ChecklistItem[];     // Subtasks/checklist
   279→  comments?: TaskComment[];        // Discussion/comments
   280→  activityLog?: ActivityLogEntry[]; // Change history
   281→
   282→  // PHASE 5 FIELDS:
   283→  subtasks?: Subtask[];            // Rich nested tasks
   284→
   285→  // PHASE A (QUICK WINS) FIELDS:
   286→  archivedAt?: string;             // ISO date (when task was archived)
   287→  lastCompletedAt?: string;        // ISO date (when moved to "done" for auto-archive)
   288→  cardNumber?: number;             // Auto-incrementing card number (KAN-1, KAN-2, etc.)
   289→
   290→  // PHASE B (KANBAN PM) FIELDS:
   291→  effort?: EffortEstimate;         // Story points (1, 2, 3, 5, 8, 13)
   292→  customStatus?: CustomStatus;     // Additional status labels (in-review, testing, deployed, blocked)
   293→  timeTracking?: TimeTracking;     // Time tracking with history
   294→
   295→  // RECURRING TASKS FIELDS (P1):
   296→  recurrence?: {
   297→    frequency: 'daily' | 'weekly' | 'monthly' | 'yearly';
   298→    interval: number; // e.g., every 2 weeks
   299→    daysOfWeek?: number[]; // 0=Sun, 1=Mon, etc. (for weekly)
   300→    dayOfMonth?: number; // 1-31 (for monthly)
   301→
   302→    // P3: Ordinal patterns ("first Monday", "last Friday")
   303→    weekOfMonth?: 1 | 2 | 3 | 4 | -1; // -1 = last
   304→    dayOfWeekInMonth?: number; // 0-6 (combined with weekOfMonth)
   305→
   306→    endType: 'never' | 'after' | 'until';
   307→    endCount?: number; // if endType='after'
   308→    endDate?: string; // if endType='until' (YYYY-MM-DD)
   309→    recurFromCompletion?: boolean; // If true, recur from completion date instead of due date (default: false)
   310→    templateId?: string; // P2: Task template to apply to recurring instances
   311→  };
   312→  recurrenceId?: string; // For recurring task instances (parent task ID)
   313→  recurrenceException?: boolean; // True if this instance was edited
   314→  isRecurringParent?: boolean; // True if this is the parent/template task
   315→  nextOccurrence?: string; // YYYY-MM-DD (calculated field)
   316→
   317→  // CUSTOM FIELDS (P2 #3):
   318→  customFields?: CustomFieldsMap; // Custom metadata fields (fieldId -> value)
   319→
   320→  // PHASE 3.1 FIELDS (TEAM COLLABORATION):
   321→  assignees?: string[];           // Array of member IDs assigned to this task
   322→
   323→  // PHASE 3.2 FIELDS (FILE ATTACHMENTS):
   324→  attachments?: TaskAttachment[]; // File attachments for this task
   325→
   326→  // PHASE 3.4 FIELDS (CARD COVERS):
   327→  coverMode?: 'fit' | 'fill'; // Cover image display mode (default: 'fit')
   328→}
   329→
   330→export interface KanbanState {
   331→  tasks: Task[];
   332→  columns: KanbanColumn[];         // Phase 4: Dynamic columns
   333→  // NOTE: dependencies moved to Task.dependencies (task-level instead of global)
   334→  archivedTasks?: Task[];          // Phase A: Archived tasks (separate from active)
   335→  nextCardNumber?: number;         // Phase A: Auto-incrementing counter for card numbers
   336→  visibleColumns?: number;         // Number of columns to show at once before scrolling (default: 5)
   337→  baseline?: ProjectBaseline | null; // Phase 1.4: Project baseline snapshot
