   568→export interface WidgetProps {
   569→  /** Unique identifier for the widget (used for persistence) */
   570→  id: string;
   571→  /** Display title shown in widget header */
   572→  title: string;
   573→  /** Category label (e.g., "Information", "Productivity") */
   574→  category?: string;
   575→  /** Additional CSS classes for the widget container */
   576→  className?: string;
   577→  /** Widget content - rendered when not loading/error */
   578→  children?: React.ReactNode;
   579→  /** Optional content displayed in header (e.g., weather stats) */
   580→  headerAccessory?: React.ReactNode;
   581→  /** Whether to show drag handle (default: true) */
   582→  draggable?: boolean;
   583→  /** Shows loading spinner instead of children when true */
   584→  loading?: boolean;
   585→  /** Shows error message with retry option when set */
   586→  error?: string | null;
   587→  /** Callback for retry/refresh button (enables refresh button in header) */
   588→  onRefresh?: () => void;
   589→}
